  1	import * as React from 'react';
  2	import { kialiStyle } from 'styles/StyleUtils';
  3	import { legendData, GraphLegendItem, GraphLegendItemRow } from './GraphLegendData';
  4	import { Button, ButtonVariant, Tooltip } from '@patternfly/react-core';
  5	import { PFColors } from 'components/Pf/PfColors';
  6	import { KialiIcon } from 'config/KialiIcon';
  7	import { useKialiTranslation } from 'utils/I18nUtils';
  8	
  9	interface GraphLegendProps {
 10	  closeLegend: () => void;
 11	}
 12	
 13	const legendBoxStyle = kialiStyle({
 14	  width: '225px',
 15	  backgroundColor: PFColors.BackgroundColor100,
 16	  border: `1px solid ${PFColors.BorderColor100}`,
 17	  overflowY: 'auto',
 18	  zIndex: 3
 19	});
 20	
 21	const headerStyle = kialiStyle({
 22	  display: 'flex',
 23	  alignItems: 'center',
 24	  justifyContent: 'space-between',
 25	  borderBottom: `1px solid ${PFColors.BorderColor100}`,
 26	  padding: '0.5rem 0 0.5rem 1rem',
 27	  fontWeight: 'bold'
 28	});
 29	
 30	const bodyStyle = kialiStyle({
 31	  padding: '0 0.5rem 1rem 1rem'
 32	});
 33	
 34	const keyStyle = kialiStyle({
 35	  minWidth: '70px',
 36	  width: '70px'
 37	});
 38	
 39	const legendItemStyle = kialiStyle({
 40	  display: 'flex',
 41	  flexDirection: 'row',
 42	  alignItems: 'center',
 43	  padding: '0.25rem 0.25rem 0 0.25rem'
 44	});
 45	
 46	const legendItemLabelStyle = kialiStyle({
 47	  fontWeight: 'normal'
 48	});
 49	
 50	const legendColumnHeadingStyle = kialiStyle({
 51	  fontWeight: 'bold',
 52	  paddingTop: '1.25rem'
 53	});
 54	
 55	const legendBadgeStyle = kialiStyle({
 56	  borderRadius: '0.25rem',
 57	  backgroundColor: '#6a6e73'
 58	});
 59	
 60	export const GraphLegend: React.FC<GraphLegendProps> = (props: GraphLegendProps) => {
 61	  const { t } = useKialiTranslation();
 62	
 63	  const renderGraphLegendList = (legendData: GraphLegendItem[]): React.ReactNode => {
 64	    return (
 65	      <>
 66	        {legendData.map((legendItem: GraphLegendItem) => (
 67	          <div key={legendItem.title} className={legendColumnHeadingStyle}>
 68	            {t(legendItem.title)}
 69	
 70	            {legendItem.data.map((legendItemRow: GraphLegendItemRow) =>
 71	              renderLegendIconAndLabel(legendItemRow, legendItem.isBadge)
 72	            )}
 73	          </div>
 74	        ))}
 75	      </>
 76	    );
 77	  };
 78	
 79	  const renderLegendIconAndLabel = (legendItemRow: GraphLegendItemRow, isBadge?: boolean): React.ReactNode => {
 80	    return (
 81	      <div key={legendItemRow.icon} className={legendItemStyle}>
 82	        <span className={keyStyle}>
 83	          <img alt={legendItemRow.label} src={legendItemRow.icon} className={isBadge ? legendBadgeStyle : ''} />
 84	        </span>
 85	
 86	        <span className={legendItemLabelStyle}>{t(legendItemRow.label)}</span>
 87	      </div>
 88	    );
 89	  };
 90	
 91	  return (
 92	    <div className={legendBoxStyle} data-test="graph-legend">
 93	      <div className={headerStyle}>
 94	        <span>{t('Legend')}</span>
 95	        <Tooltip content={t('Close Legend')}>
 96	          <Button id="legend_close" variant={ButtonVariant.plain} onClick={props.closeLegend}>
 97	            <KialiIcon.Close />
 98	          </Button>
 99	        </Tooltip>
100	      </div>
101	
102	      <div className={bodyStyle}>{renderGraphLegendList(legendData())}</div>
103	    </div>
104	  );
105	};

